prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?participant
  ?participantName
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .
  OPTIONAL { ?participant bbo:name ?participantName . }
}
ORDER BY ?participantName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  ?origId
  ?normId
  ?org
WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:belongsTo ?org .
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(STR(?origId) = "0b4394edaa09437d93cc54c78c0180cb" || STR(?normId) = "0b4394edaa09437d93cc54c78c0180cb")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?participant
  ?participantName
  ?participantType
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?participant tai:belongsTo ?choreo .
  OPTIONAL { ?participant bbo:name ?participantName . }
  OPTIONAL { ?participant a ?participantType . }
  FILTER(BOUND(?participantName) && STRLEN(STR(?participantName)) > 0)
}
ORDER BY ?participantName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?participantName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b4394edaa09437d93cc54c78c0180cb" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .

  FILTER(STRLEN(STR(?participantName)) > 0)
}
ORDER BY ?participantName
LIMIT 25
